577	  /**
578	   * Filters columns based on user role
579	   * If a column has a 'roles' property, only show it if the user's role is included
580	   * If a column has no 'roles' property, it's visible to all users
581	   */
582	  private filterColumnsByRole(colHeaders: any[], role: string): any[] {
583	    // If no role is provided, return all columns
584	    if (!role) {
585	      return colHeaders;
586	    }
587	
588	    return colHeaders.filter((col: any) => {
589	      // If column has no roles property or empty roles array, it's visible to all
590	      if (!col.roles || !Array.isArray(col.roles) || col.roles.length === 0) {
591	        return true;
592	      }
593	
594	      // Check if user's role is in the allowed roles array
595	      return col.roles.includes(role);
596	    });
597	  }
