661	  private applyColumnEditablePolicy(column: any): any {
662	    const originalEditable = column?.editable;
663	    const disableForRoles = Array.isArray(column?.disableForRoles) ? column.disableForRoles : [];
664	    const allowEditOverride = !!column?.allowEditOverride;
665	    return {
666	      ...column,
667	      editable: (params: any) => {
668	        if (disableForRoles.includes(this.getNormalizedRole())) {
669	          if (!allowEditOverride || !this.canCurrentSalesUserEditDetailCells()) {
670	            return false;
671	          }
672	        }
673	        const baseEditable =
674	          typeof originalEditable === 'function'
675	            ? !!originalEditable(params)
676	            : originalEditable !== false;
677	        if (!baseEditable) {
678	          return false;
679	        }
680	        return this.canCurrentSalesUserEditDetailCells();
681	      },
682	    };
683	  }
