785	    function formatDate(input) {
786	      if (input == null) return ''
787	      if (input.includes("-")) {
788	        var datePart = input.match(/\d+/g),
789	          year = datePart[0].substring(), // get only two digits
790	          month = datePart[1], day = datePart[2];
791	        return month + '/' + day + '/' + year;
792	      } else {
793	        return input
794	      }
795	    }
796	  }
