1280	  /** Parse a quote price into a finite number, defaulting to 0 when unparseable. */
1281	  private toPrice(value: any): number {
1282	    const numValue = typeof value === 'number' ? value : parseFloat(value);
1283	    return Number.isFinite(numValue) ? numValue : 0;
1284	  }
1285	
1286	  /**
1287	   * A vendor quote row sorts to the bottom of the detail grid when it has no
1288	   * usable price (blank / zero / negative) or the factory declined to quote
1289	   * (req_status == 1). Used by the price default-sort comparator.
1290	   */
1291	  private isUnpricedOrDeclined(data: any): boolean {
1292	    if (!data) return true;
1293	    if (data.req_status == 1) return true;
1294	    const price = this.toPrice(data?.['Price']);
1295	    return price <= 0;
1296	  }
1297	
1298	  /**
1299	   * Wires the detail grid's default sort: price ascending as the primary sort,
1300	   * with unpriced/declined rows pushed to the bottom. Mutates the matching
1301	   * colDef in place. The comparator reads the row's `Price` directly so it is
1302	   * independent of the column's colId/field/valueGetter.
1303	   */
1304	  private applyDefaultPriceSort(colHeaders: any[]): void {
1305	    if (!Array.isArray(colHeaders)) return;
1306	    const isPriceCol = (c: any) => c?.colId === 'quote_price' || c?.colId === 'price';
1307	    // Prefer a visible price column; fall back to any price column.
1308	    const priceCol =
1309	      colHeaders.find(c => isPriceCol(c) && c?.hide !== true) ||
1310	      colHeaders.find(c => isPriceCol(c));
1311	    if (!priceCol) return;
1312	
1313	    priceCol.sort = 'asc';
1314	    priceCol.sortIndex = 0;
1315	    priceCol.comparator = (_valueA: any, _valueB: any, nodeA: any, nodeB: any) => {
1316	      const aBottom = this.isUnpricedOrDeclined(nodeA?.data);
1317	      const bBottom = this.isUnpricedOrDeclined(nodeB?.data);
