  // R2 guard: when the deduction factor (1 - royalty% - dilution% - logistics% - margin%)
  // is zero or negative, the combined deductions are >= 100% and the sell price is
  // mathematically undefined. Dividing here would write Infinity / a negative price to
  // the row. Return null instead so no garbage price is persisted, and flag it.
  // NOTE: behavior for valid (positive) deductions is unchanged — same
  // `(totalCost / deduction).toFixed(2)` as before. Gen FOB math is preserved.
  if (!(deduction > 0)) {
    console.warn(
      `[getSellPrice] non-positive deduction factor (${deduction}); deductions >= 100%. ` +
      `Skipping sell-price calc to avoid Infinity/negative price.`
    );
    return null;
  }
  let sellPrice;
  return sellPrice = (totalCost / deduction).toFixed(2);

}

