  const withSortIcons = () => ({
    ...SORT_ICONS
  });

// R4: numeric columns were sorting lexicographically ("10" before "2") because
// AG Grid's default comparator string-compares values that arrive as strings.
// This comparator parses both sides as floats and sorts numerically, while
// keeping AG Grid's blank-handling contract (null/blank values sort via the
// grid's standard null ordering — we return 0 only when BOTH sides are blank).
const numericComparator = (
    valueA: any,
    valueB: any,
    _nodeA?: any,
    _nodeB?: any,
    _isInverted?: boolean
): number => {
    const a = parseFloat(valueA);
    const b = parseFloat(valueB);
    const aBlank = valueA == null || valueA === '' || isNaN(a);
    const bBlank = valueB == null || valueB === '' || isNaN(b);
    if (aBlank && bBlank) return 0;
    if (aBlank) return -1;
    if (bBlank) return 1;
    return a - b;
};

const addColumn = (
    field: string,
    colId: string,
    width: number,
    overrides: any = {}
) => {
    const { roles, numeric, ...rest } = overrides;
    return {
        field,
        colId,
        width,
        ...commonDefaults,
        icons: withSortIcons(),
        // R4: opt-in numeric sorting for numeric columns. Applied before
        // `...rest` so an explicit `comparator` override still wins.
        ...(numeric ? { comparator: numericComparator, sortable: true } : {}),
        ...rest,
        ...(roles !== undefined ? { context: { roles } } : {})
    };
};

